class Solution:
    def longestSubarray(self, arr: list[int], k: int) -> int:
        prefix_sum = {0: -1}
        curr_sum = 0
        max_len = 0
        for i, num in enumerate(arr):
            curr_sum += num
            if curr_sum - k in prefix_sum:
                max_len = max(max_len, i - prefix_sum[curr_sum - k])
            if curr_sum not in prefix_sum:
                prefix_sum[curr_sum] = i
        return max_len

